class AwsCredentialManager extends CredentialManager {

  @volatile private var currentProvider: AwsCredentialsProvider = DefaultCredentialsProvider.create()
  @volatile private var currentMode: CredentialMode = DefaultCredentials

  override def getCredentialsProvider(mode: CredentialMode): AwsCredentialsProvider = {
    mode match {
      case StaticCredentials(accessKeyId, secretAccessKey) =>
        StaticCredentialsProvider.create(
          AwsBasicCredentials.create(accessKeyId, secretAccessKey)
        )
      case SessionCredentials(accessKeyId, secretAccessKey, sessionToken) =>
        StaticCredentialsProvider.create(
          AwsSessionCredentials.create(accessKeyId, secretAccessKey, sessionToken)
        )
      case ProfileBasedCredentials(profileName) =>
        ProfileCredentialsProvider.create(profileName)
      case DefaultCredentials =>
        DefaultCredentialsProvider.create()
    }
  }

  override def rotateCredentials(newMode: CredentialMode): AwsCredentialsProvider = {
    val newProvider = getCredentialsProvider(newMode)
    currentProvider = newProvider
    currentMode = newMode
    newProvider
  }

  def getCurrentProvider: AwsCredentialsProvider = currentProvider
  def getCurrentMode: CredentialMode = currentMode
}

class S3Service(config: AwsConfig, credentialManager: AwsCredentialManager) {

  private lazy val s3Client: S3Client = S3Client.builder()
