    val request = CreateBucketRequest.builder().bucket(bucketName).build()
    s3Client.createBucket(request)
    s"Bucket '$bucketName' created successfully"
  }

  def deleteBucket(bucketName: String): Try[String] = Try {
    val request = DeleteBucketRequest.builder().bucket(bucketName).build()
    s3Client.deleteBucket(request)
    s"Bucket '$bucketName' deleted successfully"
  }

  def listObjects(bucketName: String, prefix: Option[String] = None): Try[List[S3Object]] = Try {
    val requestBuilder = ListObjectsV2Request.builder().bucket(bucketName)
    prefix.foreach(p => requestBuilder.prefix(p))
    val response = s3Client.listObjectsV2(requestBuilder.build())
    response.contents().asScala.toList
  }

  def putObject(bucketName: String, key: String, content: String): Try[String] = Try {
    val request = PutObjectRequest.builder()
      .bucket(bucketName)
      .key(key)
      .build()
    s3Client.putObject(request, RequestBody.fromString(content))
    s"Object '$key' uploaded to bucket '$bucketName'"
  }

  def getObject(bucketName: String, key: String): Try[String] = Try {
    val request = GetObjectRequest.builder()
      .bucket(bucketName)
      .key(key)
      .build()
    val responseInputStream = s3Client.getObject(request)
    val content = new String(responseInputStream.readAllBytes())
    responseInputStream.close()
